package com.auction.app.service.impl;

import com.app.common.entity.Bidder;
import com.app.common.entity.User;
import com.auction.app.repository.UserDAO;
import org.junit.jupiter.api.Test;

import java.util.ArrayList;
import java.util.List;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertSame;
import static org.junit.jupiter.api.Assertions.assertThrows;

class UserServiceImplTest {
    @Test
    void registerRejectsDuplicateUsername() {
        FakeUserDAO userDAO = new FakeUserDAO();
        Bidder existingUser = new Bidder("alice", "pass", "alice@example.com");
        userDAO.save(existingUser);

        UserServiceImpl service = new UserServiceImpl(userDAO);

        IllegalArgumentException exception = assertThrows(
                IllegalArgumentException.class,
                () -> service.register(new Bidder("alice", "other", "alice2@example.com"))
        );
        assertEquals("Username already exist", exception.getMessage());
    }

    @Test
    void loginReturnsMatchingUser() {
        FakeUserDAO userDAO = new FakeUserDAO();
        Bidder user = new Bidder("alice", "pass", "alice@example.com");
        userDAO.save(user);

        UserServiceImpl service = new UserServiceImpl(userDAO);

        assertSame(user, service.login("alice", "pass"));
    }

    @Test
    void loginRejectsWrongPassword() {
        FakeUserDAO userDAO = new FakeUserDAO();
        userDAO.save(new Bidder("alice", "pass", "alice@example.com"));

        UserServiceImpl service = new UserServiceImpl(userDAO);

        assertThrows(IllegalArgumentException.class, () -> service.login("alice", "wrong"));
    }

    private static class FakeUserDAO implements UserDAO {
        private final List<User> users = new ArrayList<>();

        @Override
        public User findByUsername(String username) {
            return users.stream()
                    .filter(user -> user.getUsername().equals(username))
                    .findFirst()
                    .orElse(null);
        }

        @Override
        public User findById(String id) {
            return users.stream()
                    .filter(user -> user.getId().equals(id))
                    .findFirst()
                    .orElse(null);
        }

        @Override
        public List<User> findAll() {
            return users;
        }

        @Override
        public boolean save(User entity) {
            users.add(entity);
            return true;
        }

        @Override
        public boolean delete(String id) {
            return users.removeIf(user -> user.getId().equals(id));
        }
    }
}

package com.auction.app.service.impl;

import com.app.common.entity.Bidder;
import com.app.common.entity.User;
import com.auction.app.repository.UserDAO;
import org.junit.jupiter.api.Test;

import java.util.ArrayList;
import java.util.List;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertSame;
import static org.junit.jupiter.api.Assertions.assertThrows;

class UserServiceImplTest {
    @Test
    void registerRejectsDuplicateUsername() {
        FakeUserDAO userDAO = new FakeUserDAO();
        Bidder existingUser = new Bidder("alice", "pass", "alice@example.com");
        userDAO.save(existingUser);

        UserServiceImpl service = new UserServiceImpl(userDAO);

        IllegalArgumentException exception = assertThrows(
                IllegalArgumentException.class,
                () -> service.register(new Bidder("alice", "other", "alice2@example.com"))
        );
        assertEquals("Username already exist", exception.getMessage());
    }

    @Test
    void loginReturnsMatchingUser() {
        FakeUserDAO userDAO = new FakeUserDAO();
        Bidder user = new Bidder("alice", "pass", "alice@example.com");
        userDAO.save(user);

        UserServiceImpl service = new UserServiceImpl(userDAO);

        assertSame(user, service.login("alice", "pass"));
    }

    @Test
    void loginRejectsWrongPassword() {
        FakeUserDAO userDAO = new FakeUserDAO();
        userDAO.save(new Bidder("alice", "pass", "alice@example.com"));

        UserServiceImpl service = new UserServiceImpl(userDAO);

        assertThrows(com.app.common.exception.UserAuthException.class, () -> service.login("alice", "wrong"));
    }

    private static class FakeUserDAO implements UserDAO {
        private final List<User> users = new ArrayList<>();

        @Override
        public User findByUsername(String username) {
            return users.stream()
                    .filter(user -> user.getUsername().equals(username))
                    .findFirst()
                    .orElse(null);
        }

        @Override
        public User findById(String id) {
            return users.stream()
                    .filter(user -> user.getId().equals(id))
                    .findFirst()
                    .orElse(null);
        }

        @Override
        public List<User> findAll() {
            return users;
        }

        @Override
        public boolean save(User entity) {
            users.add(entity);
            return true;
        }

        @Override
        public boolean delete(String id) {
            return users.removeIf(user -> user.getId().equals(id));
        }
    }
}

package com.auction.client;

import com.auction.client.service.AuctionSocketClient;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

/**
 * SimpleConsoleClient: Ví dụ nhỏ chạy trên console để tương tác với AuctionServer
 * Mục đích: Demo cách dùng AuctionSocketClient
 */
public class SimpleConsoleClient {
    public static void main(String[] args) {
        AuctionSocketClient client = new AuctionSocketClient();
        try {
            client.connect("localhost", 5000, event -> System.out.println("[EVENT] " + event));

            BufferedReader console = new BufferedReader(new InputStreamReader(System.in));
            System.out.println("Nhập HELP để xem lệnh mẫu, hoặc QUIT để thoát.");

            while (true) {
                System.out.print("> ");
                String line = console.readLine();
                if (line == null) break;
                line = line.trim();
                if (line.isEmpty()) continue;
                if (line.equalsIgnoreCase("QUIT") || line.equalsIgnoreCase("EXIT")) {
                    client.disconnect();
                    break;
                }
                try {
                    String resp = client.sendCommand(line);
                    System.out.println("< SERVER RESPONSE: " + resp);
                } catch (IOException e) {
                    System.err.println("Error sending command: " + e.getMessage());
                    break;
                }
            }

        } catch (IOException e) {
            System.err.println("Cannot connect to server: " + e.getMessage());
        } finally {
            client.disconnect();
        }
    }
}

package com.auction.client.service;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.net.Socket;
import java.net.UnknownHostException;
import java.util.function.Consumer;

/**
 * AuctionSocketClient: Lớp tiện ích để kết nối tới AuctionSocketServer
 * - Kết nối TCP socket tới server
 * - Gửi lệnh dạng text (như trong protocol của server)
 * - Lắng nghe responses và sự kiện realtime (EVENT|...)
 *
 * Usage:
 *   AuctionSocketClient client = new AuctionSocketClient();
 *   client.connect("localhost", 5000, line -> System.out.println("EVENT: " + line));
 *   String resp = client.sendCommand("HELP");
 */
public class AuctionSocketClient {
    private Socket socket;
    private PrintWriter writer;
    private BufferedReader reader;
    private Thread listenerThread;
    private volatile boolean running;

    /**
     * Kết nối tới server và bắt đầu listener thread để nhận các dòng trả về
     * @param host địa chỉ server
     * @param port cổng
     * @param eventHandler callback nhận các dòng bắt đầu bằng "EVENT|" (realtime)
     * @throws IOException khi không kết nối được
     */
    public void connect(String host, int port, Consumer<String> eventHandler) throws IOException {
        try {
            socket = new Socket(host, port);
            writer = new PrintWriter(socket.getOutputStream(), true);
            reader = new BufferedReader(new InputStreamReader(socket.getInputStream()));

            // Đọc dòng chào mừng đầu tiên (server gửi khi kết nối)
            String welcome = reader.readLine();
            if (welcome != null) {
                // Có thể xử lý welcome nếu cần
                System.out.println("SERVER: " + welcome);
            }

            running = true;
            listenerThread = new Thread(() -> {
                try {
                    String line;
                    while (running && (line = reader.readLine()) != null) {
                        // Nếu là sự kiện realtime, chuyển cho handler
                        if (line.startsWith("EVENT|") && eventHandler != null) {
                            try {
                                eventHandler.accept(line);
                            } catch (Exception ignored) {
                            }
                        } else {
                            // Non-event dòng: in ra để debug
                            System.out.println("SERVER: " + line);
                        }
                    }
                } catch (IOException e) {
                    if (running) {
                        System.err.println("Listener error: " + e.getMessage());
                    }
                }
            }, "auction-client-listener");
            listenerThread.setDaemon(true);
            listenerThread.start();

        } catch (UnknownHostException e) {
            throw new IOException("Unknown host: " + host, e);
        }
    }

    /**
     * Gửi 1 command tới server và chờ 1 dòng phản hồi (blocking)
     * NOTE: Server có thể gửi thêm EVENTs bất kỳ lúc nào - listener sẽ in/forward chúng.
     * @param command ví dụ: "LOGIN alice pass" hoặc "PLACE_BID auctionId bidderId 100"
     * @return dòng phản hồi đầu tiên từ server (có thể là OK|... hoặc ERR|...)
     * @throws IOException khi đọc/ghi lỗi
     */
    public synchronized String sendCommand(String command) throws IOException {
        if (socket == null || socket.isClosed()) {
            throw new IOException("Not connected to server");
        }
        // Ghi lệnh xuống server
        writer.println(command);
        // Đọc trả lời ngay sau đó (blocking)
        String response = reader.readLine();
        return response;
    }

    /**
     * Ngắt kết nối và stop listener
     */
    public void disconnect() {
        running = false;
        try {
            if (socket != null && !socket.isClosed()) {
                try {
                    writer.println("QUIT");
                } catch (Exception ignored) {
                }
                socket.close();
            }
        } catch (IOException e) {
            System.err.println("Error while disconnecting: " + e.getMessage());
        }
    }

    // Convenience methods for common commands
    public String help() throws IOException { return sendCommand("HELP"); }
    public String login(String username, String password) throws IOException { return sendCommand("LOGIN " + username + " " + password); }
    public String registerBidder(String username, String password, String email) throws IOException { return sendCommand("REGISTER_BIDDER " + username + " " + password + " " + email); }
    public String deposit(String userId, double amount) throws IOException { return sendCommand("DEPOSIT " + userId + " " + amount); }
    public String listAuctions() throws IOException { return sendCommand("LIST_AUCTIONS"); }
    public String placeBid(String auctionId, String bidderId, double amount) throws IOException { return sendCommand("PLACE_BID " + auctionId + " " + bidderId + " " + amount); }
}
